class Solution:
    def shortestMatchingSubstring(self, s: str, p: str) -> int:
        def match(s, p):
            if not p:
                return not s
            if p[0] == '*':
                return match(s, p[1:]) or (s and match(s[1:], p))
            return s and s[0] == p[0] and match(s[1:], p[1:])

        min_len = float('inf')
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                if match(s[i:j], p):
                    min_len = min(min_len, j - i)
        return min_len if min_len != float('inf') else -1
